INSERT INTO `site_settings` (`id`, `key`, `locale`, `value`) VALUES
(UUID(), 'about_page', 'tr', '{"hero": {"title": "Hakkımızda", "description": "vistaseeds, resmi Vista Seeds anlatısını; ürün, bilgi bankası, referanslar, bayi ağı ve toplu satış modülleriyle aynı ekosistemde birleştiren dijital tarım yüzeyidir.", "image_url": "/uploads/about/vistaseeds/about-hero-01KKF5X2J4JPW5KXVEYN9WEH7E.webp", "image_alt": "Vista Seeds Hakkımızda görseli"}, "intro": {"title": "Tarımın Geleceğini Şekillendiren Çok Katmanlı Yapı", "subtitle": "Kaynak içerik doğrudan vistaseeds.com.tr üzerinden alınmıştır", "content": "Vista Seeds, köklü bir geçmişe sahip Atakan Tohum İnşaat Mühendislik bünyesinde, tarımın geleceğini şekillendirmek amacıyla kurulmuş öncü bir markadır. Faaliyetlerini yalnızca tohum ıslahı ve üretimiyle sınırlı tutmayıp; tarım, yenilenebilir enerji ve inşaat sektörlerindeki yatırımlarıyla çok yönlü bir yapı sunar. vistaseeds bu kurumsal anlatıyı dijital ürün kataloğu, referans yönetimi, bilgi bankası ve satış akışlarıyla erişilebilir hale getirir."}, "vision": {"title": "Vizyonumuz", "content": "Tarımda teknoloji ve doğayı buluşturan inovatif çözümlerle global standartlarda bir marka olmak; yenilenebilir enerji ve modern mühendislik projeleriyle entegre büyüyen, verimli ve çevreci bir gelecek kurmak."}, "mission": {"title": "Misyonumuz", "content": "Yüksek genetik potansiyele sahip, tescilli ve dayanıklı tohum çeşitleriyle üreticilerin verimliliğini artırmak; inovasyon, kalite ve sürdürülebilirliği temel alan güvenilir bir çözüm ortağı olmak."}, "values": [{"title": "Yüksek Genetik Potansiyel", "description": "Kaynak sitede vurgulanan tescilli, dayanıklı ve yüksek verimli tohum yaklaşımını veri odaklı ürün yüzeylerine taşır.", "icon": "sprout"}, {"title": "Sürdürülebilir Üretim", "description": "Bereket Fide ve enerji yatırımlarıyla desteklenen çevreye duyarlı yaklaşımı; içerik, teklif ve saha akışlarına yansıtır.", "icon": "shield"}, {"title": "Çok Yönlü Kurumsal Yapı", "description": "Tarım, yenilenebilir enerji ve inşaat yatırımlarını tek kurumsal çatı içinde görünür kılar.", "icon": "users"}, {"title": "Dijital Erişilebilirlik", "description": "Referanslar, bilgi bankası ve bayi akışı ile kurumsal gücü sadece metin değil, etkileşimli ekranlarla sunar.", "icon": "flask"}], "stats": [{"value": "1988", "label": "İlk Tarım Adımı", "description": "Kaynak zaman çizgisi"}, {"value": "2006", "label": "Bereket Fide", "description": "Kuruluş yılı"}, {"value": "100+", "label": "Uzman Kadro", "description": "Ana sayfa kaynağı"}, {"value": "250+", "label": "Saha Ekibi", "description": "Ana sayfa kaynağı"}], "timeline": [{"year": "1988", "title": "Tarım sektörüne ilk adım", "description": "Ana sayfadaki stratejik adımlar zaman çizgisinde verilen ilk kurumsal eşik."}, {"year": "1990", "title": "Şahin Ziraat kuruluşu", "description": "Tarım odağındaki erken kurumsal yapılanma."}, {"year": "2006", "title": "Bereket Fide’nin kuruluşu", "description": "Üretim zincirini destekleyen fide operasyonunun başlangıcı."}, {"year": "2017", "title": "İnşaat sektörüne giriş", "description": "Kurumsal yapının farklı yatırım alanlarına genişlemesi."}, {"year": "2018", "title": "Tolkan Mimarlık", "description": "Mühendislik ve proje deneyiminin güçlenmesi."}, {"year": "2025", "title": "Atakan Tohum ve Vista Seeds kuruluşu", "description": "Tohum markasının mevcut kurumsal yüzeyde görünür hale gelmesi."}], "activities": {"title": "Ekosistem Modülleri", "items": [{"title": "Ürün ve Çeşit Yönetimi", "description": "Tohum portföyünü filtrelenebilir, karşılaştırılabilir ve metadata tabanlı ürün ekranlarıyla sunar."}, {"title": "Referans ve Proje Yüzeyi", "description": "Grup şirketleri ve proje galerilerini yerel storage destekli medya akışıyla yayınlar."}, {"title": "Bilgi Bankası ve Blog", "description": "Teknik içerik, ekim rehberi ve editoryal içerikleri karar destek yüzeyi haline getirir."}, {"title": "Bayi ve Toplu Satış Akışı", "description": "Bölgesel erişim, teklif ve kurumsal tedarik süreçlerini aynı deneyime bağlar."}]}, "feature_panels": [{"title": "Tohumun Bereketi", "description": "Tarımda başarının doğru tohumla başladığını vurgulayan ana kurumsal mesaj.", "image_url": "/uploads/about/vistaseeds/features/hero-seed-01KKF1351HG1HJ9VJ2NCNC1EA7.webp", "image_alt": "Vista Seeds tohumun bereketi görseli"}, {"title": "Yüksek Verimli Tohumlar", "description": "Modern üretim teknikleriyle geliştirilen yüksek verimli tohum yaklaşımı.", "image_url": "/uploads/about/vistaseeds/features/high-yield-01KKBNPQNZ111C9XNQ5SZR917C.webp", "image_alt": "Yüksek verimli tohumlar görseli"}, {"title": "Sürdürülebilir Tarım Anlayışı", "description": "Yenilenebilir enerji ve çevreye duyarlı üretim modelinin görsel yüzeyi.", "image_url": "/uploads/about/vistaseeds/features/sustainability-01KKBP4H1ZRJG4NC56YH86XW1K.webp", "image_alt": "Sürdürülebilir tarım anlayışı görseli"}, {"title": "Kalite ve Güven", "description": "Tescilli çeşitler, üretici odaklı yaklaşım ve güçlü kurumsal altyapı vurgusu.", "image_url": "/uploads/about/vistaseeds/features/quality-trust-01KKBP4HBBKX99XTFY3PV0YNVD.webp", "image_alt": "Kalite ve güven görseli"}]}')
