-- Vista Seeds about-page refresh from official source
-- Source: https://www.vistaseeds.com.tr/hakkimizda and homepage media blocks
SET NAMES utf8mb4;
SET time_zone = '+00:00';

DELETE FROM `storage_assets` WHERE id LIKE '14609400-%';

ON DUPLICATE KEY UPDATE `value` = VALUES(`value`), `updated_at` = NOW(3);
